export function getTranslations(lang: string = 'en'): Record<string, string> {
    const langMap: Record<string, LangKey> = {
        'en': 'en', 'en-US': 'en', 'en-GB': 'en',
        'vi': 'vi', 'vi-VN': 'vi',
        'es': 'es', 'es-ES': 'es', 'es-MX': 'es',
        'fr': 'fr', 'fr-FR': 'fr',
        'de': 'de', 'de-DE': 'de',
        'ja': 'ja', 'ja-JP': 'ja',
        'zh': 'zh', 'zh-CN': 'zh', 'zh-TW': 'zh',
        'ko': 'ko', 'ko-KR': 'ko',
        'pt': 'pt', 'pt-BR': 'pt', 'pt-PT': 'pt',
        'th': 'th', 'th-TH': 'th',
        'id': 'id', 'id-ID': 'id',
        'ar': 'ar', 'ar-SA': 'ar', 'ar-AE': 'ar',
        'ru': 'ru', 'ru-RU': 'ru',
        'uk': 'uk', 'uk-UA': 'uk',
        'hi': 'hi', 'hi-IN': 'hi',
        'bn': 'bn', 'bn-BD': 'bn',
        'it': 'it', 'it-IT': 'it',
        'pl': 'pl', 'pl-PL': 'pl',
        'nl': 'nl', 'nl-NL': 'nl',
        'tr': 'tr', 'tr-TR': 'tr',
        'el': 'el', 'el-GR': 'el',
        'sv': 'sv', 'sv-SE': 'sv',
        'no': 'no', 'no-NO': 'no',
        'tl': 'tl', 'tl-PH': 'tl',
        'ms': 'ms', 'ms-MY': 'ms'
    };
    const key = langMap[lang] || 'en';
    return translations[key];
}

// Helper function to get language key from country code
export function getLanguageFromCountry(countryCode: string): LangKey {
    const languageCode = getLanguageForCountry(countryCode);
    
    // Cast the LanguageCode to LangKey (they should be compatible)
    return languageCode as LangKey;
}
